import { chromium } from 'playwright';
import { readFileSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const cookiesPath = join(__dirname, 'devops_cookies.json');
const screenshotDir = __dirname;

async function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

async function main() {
  const cookies = JSON.parse(readFileSync(cookiesPath, 'utf-8'));

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });

  // Add cookies
  await context.addCookies(cookies);

  const page = await context.newPage();

  console.log('=== Navigating to pipelines page ===');
  await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines', {
    waitUntil: 'networkidle',
    timeout: 30000,
  });

  await sleep(2000);

  // Check if we're on login page
  const currentUrl = page.url();
  console.log('Current URL:', currentUrl);

  // Screenshot of initial page
  await page.screenshot({ path: join(screenshotDir, 'pipeline_list.png'), fullPage: true });
  console.log('Screenshot saved: pipeline_list.png');

  // Get page title and content
  const title = await page.title();
  console.log('Page title:', title);

  // Check page content
  const bodyText = await page.evaluate(() => document.body.innerText.substring(0, 2000));
  console.log('Body text (first 2000 chars):', bodyText);

  // Look for "1v1-测试服" pipeline
  console.log('\n=== Looking for 1v1-测试服 pipeline ===');

  // Try to find the pipeline
  const pipelineLocator = page.locator('text=1v1-测试服').first();
  const pipelineExists = await pipelineLocator.count();
  console.log('Pipeline element count:', pipelineExists);

  if (pipelineExists > 0) {
    console.log('Found pipeline! Clicking...');
    await pipelineLocator.click();
    await sleep(2000);
    await page.waitForLoadState('networkidle');

    const afterClickUrl = page.url();
    console.log('URL after click:', afterClickUrl);

    await page.screenshot({ path: join(screenshotDir, 'pipeline_detail.png'), fullPage: true });
    console.log('Screenshot saved: pipeline_detail.png');

    const detailText = await page.evaluate(() => document.body.innerText.substring(0, 5000));
    console.log('Detail page text:', detailText);
  } else {
    // Try to get all pipeline names
    console.log('Pipeline not found directly, getting all text...');
    const allText = await page.evaluate(() => document.body.innerText);
    console.log('Full page text:', allText.substring(0, 10000));

    // Try different selectors
    const links = await page.evaluate(() => {
      return Array.from(document.querySelectorAll('a, [role="link"], .pipeline-name, .pipeline-item'))
        .map(el => ({ text: el.innerText, href: el.href || '' }))
        .filter(item => item.text.trim());
    });
    console.log('All links/items:', JSON.stringify(links.slice(0, 50), null, 2));
  }

  // Try searching for pipeline if not found
  if (pipelineExists === 0) {
    // Look for search input
    const searchInput = page.locator('input[placeholder*="搜索"], input[type="search"], input[placeholder*="search"]').first();
    const searchCount = await searchInput.count();

    if (searchCount > 0) {
      console.log('Found search input, searching for 1v1...');
      await searchInput.fill('1v1');
      await sleep(1500);
      await page.screenshot({ path: join(screenshotDir, 'pipeline_search.png'), fullPage: true });

      const searchResults = await page.evaluate(() => document.body.innerText.substring(0, 5000));
      console.log('Search results:', searchResults);

      // Try clicking on result
      const result = page.locator('text=1v1-测试服').first();
      if (await result.count() > 0) {
        await result.click();
        await sleep(2000);
        await page.waitForLoadState('networkidle');
        await page.screenshot({ path: join(screenshotDir, 'pipeline_detail_after_search.png'), fullPage: true });
        const detailText2 = await page.evaluate(() => document.body.innerText);
        console.log('Detail after search:', detailText2.substring(0, 8000));
      }
    }
  }

  await browser.close();
  console.log('=== Done ===');
}

main().catch(console.error);

import { chromium } from 'playwright';
import { readFileSync, writeFileSync } from 'fs';
