  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });

  await context.addCookies(cookies);
  const page = await context.newPage();

  // Go directly to the pipeline page we found
  console.log('=== Going directly to 1v1-测试服 pipeline ===');
  await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a?buildId=b-a872a3a41313452db446a47f694247f2', {
    waitUntil: 'networkidle',
    timeout: 30000,
  });
  await sleep(2000);

  // Get full build detail text
  const fullText = await page.evaluate(() => document.body.innerText);
  console.log('=== FULL PAGE TEXT (build detail) ===');
  console.log(fullText.substring(0, 15000));

  // Get all stage/step names
  const stages = await page.evaluate(() => {
    const stageEls = document.querySelectorAll('[class*="stage"], [class*="step"], [class*="job"]');
    return Array.from(stageEls).map(el => el.innerText.trim()).filter(t => t.length > 0);
  });
  console.log('\n=== STAGES/STEPS ===');
  console.log(JSON.stringify(stages.slice(0, 50), null, 2));

  // Click on "打配置" step to see its log
  await page.screenshot({ path: join(__dirname, 'pipeline_build_detail.png'), fullPage: true });

  // Try to find the edit/configure button for the pipeline
  // Look for "配置" or "编辑" button
  const configBtn = page.locator('text=配置', { exact: true }).first();
  const configBtnCount = await configBtn.count();
  console.log('\nConfig button count:', configBtnCount);

  // Try clicking on individual steps to see their logs
  const stepNames = ['打配置', 'build+替换', '重启服务'];
  for (const stepName of stepNames) {
    const stepEl = page.locator(`text=${stepName}`).first();
    if (await stepEl.count() > 0) {
      console.log(`\n=== Clicking on step: ${stepName} ===`);
      await stepEl.click();
      await sleep(1000);

      // Get log content
      const logText = await page.evaluate(() => {
        const logEls = document.querySelectorAll('[class*="log"], [class*="console"], pre, code');
        return Array.from(logEls).map(el => el.innerText).join('\n---\n');
      });

      if (logText.trim()) {
        console.log(`Log for ${stepName}:`, logText.substring(0, 3000));
      }

      const stepText = await page.evaluate(() => document.body.innerText);
      console.log(`Page after clicking ${stepName}:`, stepText.substring(0, 3000));
    }
  }

  // Now try to go to the pipeline edit/configure page
  console.log('\n=== Looking for pipeline configure page ===');
  await page.goto('https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a', {
    waitUntil: 'networkidle',
    timeout: 30000,
  });
  await sleep(2000);

  const configPageText = await page.evaluate(() => document.body.innerText);
  console.log('\n=== Pipeline main page text ===');
  console.log(configPageText.substring(0, 10000));

  await page.screenshot({ path: join(__dirname, 'pipeline_config.png'), fullPage: true });

  // Look for any edit/configure links
  const allLinks = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('a, button'))
      .map(el => ({ text: el.innerText.trim(), href: el.href || '', type: el.tagName }))
      .filter(item => item.text.length > 0 && item.text.length < 50);
  });
  console.log('\n=== All links/buttons ===');
  console.log(JSON.stringify(allLinks.slice(0, 80), null, 2));

  await browser.close();
  console.log('\n=== Done ===');
}

main().catch(console.error);

