import { chromium } from 'playwright';
import { readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const cookiesPath = join(__dirname, 'devops_cookies.json');

async function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

async function main() {
  const cookies = JSON.parse(readFileSync(cookiesPath, 'utf-8'));

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });

  await context.addCookies(cookies);
  const page = await context.newPage();

  const pipelineId = 'p-f78c977835c84b71a6d58b4746cd1c4a';

  // Go to edit page
  await page.goto(`https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${pipelineId}/edit`, {
    waitUntil: 'networkidle',
    timeout: 30000,
  });
  await sleep(2000);

  // Click build+替换 step using Escape first if drawer is open, then click
  const escKey = async () => {
    await page.keyboard.press('Escape');
    await sleep(500);
  };

  await escKey();

  // Get all clickable elements
  const elements = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('[class*="name"]'))
      .map(el => ({ text: el.innerText, class: el.className }))
      .filter(e => e.text.trim().length > 0);
  });
  console.log('Name elements:', JSON.stringify(elements.slice(0, 20), null, 2));

  // Click on build+替换 using nth
  const allStepNames = page.locator('.name');
  const cnt = await allStepNames.count();
  console.log('Total .name elements:', cnt);

  for (let i = 0; i < cnt; i++) {
    const text = await allStepNames.nth(i).innerText();
    console.log(`  [${i}] ${text}`);
  }

  // Find and click "build+替换"
  for (let i = 0; i < cnt; i++) {
    const text = await allStepNames.nth(i).innerText();
    if (text.includes('build') || text.includes('替换')) {
      console.log('\nClicking build+替换 at index', i);
      await allStepNames.nth(i).click();
      await sleep(2000);
      break;
    }
  }

  const buildText = await page.evaluate(() => document.body.innerText);
  console.log('\nbuild+替换 config:', buildText.substring(0, 6000));
  await page.screenshot({ path: join(__dirname, 'edit_step_build.png'), fullPage: true });

  // Close drawer and click 重启服务
  await escKey();
  await sleep(500);

  for (let i = 0; i < cnt; i++) {
    const text = await allStepNames.nth(i).innerText();
    if (text.includes('重启')) {
      console.log('\nClicking 重启服务 at index', i);
      await allStepNames.nth(i).click();
      await sleep(2000);
      break;
    }
  }

  const restartText = await page.evaluate(() => document.body.innerText);
  console.log('\n重启服务 config:', restartText.substring(0, 6000));
  await page.screenshot({ path: join(__dirname, 'edit_step_restart.png'), fullPage: true });

  await browser.close();
  console.log('\n=== Done ===');
}

